safeHandle('save-sale', (_, sale) => {
  if (sale.id) {
    getDb().prepare('UPDATE sales SET total=?, discount=?, payment_method=?, amount_paid=?, change_amount=?, items=?, payment_breakdown=?, change_return_method=? WHERE id=?')
      .run(sale.total, sale.discount, sale.paymentMethod, sale.amountPaid !== undefined ? sale.amountPaid : sale.total, sale.changeAmount || 0, JSON.stringify(sale.items), sale.paymentBreakdown ? JSON.stringify(sale.paymentBreakdown) : null, sale.changeReturnMethod || null, sale.id);
    logAudit('Updated Sale', `Sale ID ${sale.id} updated (Method: ${sale.paymentMethod})`);
    return { id: sale.id };
  } else {
    const info = getDb().prepare('INSERT INTO sales (total, discount, payment_method, amount_paid, change_amount, items, payment_breakdown, change_return_method) VALUES (?, ?, ?, ?, ?, ?, ?, ?)')
      .run(sale.total, sale.discount, sale.paymentMethod, sale.amountPaid !== undefined ? sale.amountPaid : sale.total, sale.changeAmount || 0, JSON.stringify(sale.items), sale.paymentBreakdown ? JSON.stringify(sale.paymentBreakdown) : null, sale.changeReturnMethod || null);

    const updateStock = getDb().prepare('UPDATE products SET stock = stock - ? WHERE id = ?');
    sale.items.forEach(item => {
      updateStock.run(item.qty, item.id);
    });
    return { id: info.lastInsertRowid };
  }
});

safeHandle('get-sales', () => {
  try {
    const rawSales = getDb().prepare('SELECT * FROM sales ORDER BY date DESC').all();
    return rawSales.map(s => {
      let items = [];
      let paymentBreakdown = [];
      try { items = JSON.parse(s.items || '[]'); } catch (e) { logError('ParseSaleItems', e); }
      try { paymentBreakdown = JSON.parse(s.payment_breakdown || '[]'); } catch (e) { /* ignore */ }

      return { 
        ...s, 
        items,
        amountPaid: s.amount_paid,
        changeAmount: s.change_amount,
        paymentMethod: s.payment_method,
        paymentBreakdown: paymentBreakdown.length > 0 ? paymentBreakdown : [{ method: s.payment_method || 'cash', amount: s.amount_paid || s.total }],
        changeReturnMethod: s.change_return_method
      };
    });
  } catch (err) {
    logError('GetSales', err);
    return [];
  }
});

safeHandle('delete-sale', (_, id) => {
  const sale = getDb().prepare('SELECT * FROM sales WHERE id = ?').get(id);
  if (!sale) return false;

  const items = JSON.parse(sale.items);
  const restoreStock = getDb().prepare('UPDATE products SET stock = stock + ? WHERE id = ?');

  const transaction = getDb().transaction(() => {
    items.forEach(item => restoreStock.run(item.qty, item.id));
    getDb().prepare('DELETE FROM sales WHERE id = ?').run(id);
  });

  transaction();
  logAudit('Deleted Sale', `Sale ID ${id} deleted (Total: ${sale.total})`);
  return true;
});

// ─── IPC: Expenses ───
safeHandle('get-expenses', () => {
  return getDb().prepare('SELECT * FROM expenses ORDER BY date DESC').all();
});

safeHandle('save-expense', (_, e) => {
  const info = getDb().prepare('INSERT INTO expenses (date, category, description, amount, payment_method) VALUES (?, ?, ?, ?, ?)')
    .run(e.date, e.category, e.description, e.amount, e.paymentMethod);
  return { id: info.lastInsertRowid };
});

safeHandle('delete-expense', (_, id) => {
  getDb().prepare('DELETE FROM expenses WHERE id=?').run(id);
  return true;
});

// ─── IPC: Purchases ───
safeHandle('get-purchases', () => {
  return getDb().prepare('SELECT * FROM purchases ORDER BY date DESC').all();
});

safeHandle('save-purchase', (_, p) => {
  const insert = getDb().prepare('INSERT OR REPLACE INTO purchases (id, date, supplier, invoice, items_count, total, paid, status, payment_method) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)');
  insert.run(p.id, p.date, p.supplier, p.invoice, p.items, p.total, p.paid, p.status, p.paymentMethod);
  return true;
});

safeHandle('delete-purchase', (_, id) => {
  getDb().prepare('DELETE FROM purchases WHERE id=?').run(id);
  return true;
});

// ─── IPC: Categories ───
safeHandle('get-categories', () => {
  return getDb().prepare('SELECT * FROM categories ORDER BY name').all();
});

safeHandle('save-category', (_, cat) => {
  if (cat.id) {
    getDb().prepare('UPDATE categories SET name=? WHERE id=?').run(cat.name, cat.id);
    return cat;
  } else {
    const info = getDb().prepare('INSERT INTO categories (name) VALUES (?)').run(cat.name);
    return { ...cat, id: info.lastInsertRowid };
  }
});

safeHandle('delete-category', (_, id) => {
  getDb().prepare('DELETE FROM categories WHERE id=?').run(id);
  return true;
});

// ─── IPC: Suppliers ───
safeHandle('get-suppliers', () => {
  return getDb().prepare('SELECT * FROM suppliers ORDER BY name').all();
});

safeHandle('save-supplier', (_, s) => {
  if (s.id) {
    getDb().prepare('UPDATE suppliers SET name=?, phone=?, email=?, address=? WHERE id=?')
      .run(s.name, s.phone || null, s.email || null, s.address || null, s.id);
    return s;
  } else {
    const info = getDb().prepare('INSERT INTO suppliers (name, phone, email, address) VALUES (?, ?, ?, ?)')
      .run(s.name, s.phone || null, s.email || null, s.address || null);
    return { ...s, id: info.lastInsertRowid };
  }
});

safeHandle('delete-supplier', (_, id) => {
  getDb().prepare('DELETE FROM suppliers WHERE id=?').run(id);
  return true;
});

safeHandle('add-supplier', (_, name) => {
  const info = getDb().prepare('INSERT INTO suppliers (name) VALUES (?)').run(name);
  return { id: info.lastInsertRowid };
});

// ─── IPC: Cloud Sync ───
safeHandle('sync-to-cloud', async () => {
  return await runFullSync(getDb());
});

safeHandle('get-last-sync-time', () => {
  return getLastSyncTime(getDb());
});

// ─── IPC: Receipt Download ───
safeHandle('download-receipt', async (_, sale) => {
  const rows = getDb().prepare('SELECT * FROM settings').all();
  const settings = {};
  rows.forEach(r => {
    try { settings[r.key] = JSON.parse(r.value); } catch { settings[r.key] = r.value; }
  });
  return await downloadReceiptPDF(mainWindow, sale, settings);
});

import { createRequire } from 'module';
const require = createRequire(import.meta.url);
const { machineIdSync } = require('node-machine-id');
import os from 'os';
import { app } from 'electron';
import { supabase } from './supabase.js';

let deviceId = null;

try {
  // Use machineIdSync to get a stable, unique ID for this hardware
  deviceId = machineIdSync();
} catch (error) {
  console.error("Failed to generate machine ID:", error);
  deviceId = "unknown-" + Math.random().toString(36).substring(7);
}

const getDeviceInfo = () => {
  return {
    device_id: deviceId,
    app_version: app.getVersion(),
    device_name: os.hostname(),
    os: os.platform(),
    last_seen: new Date().toISOString()
  };
};

export const syncDeviceTelemetry = async () => {
  try {
    // Check for Force Actions from Developer Dashboard
    const { data: remoteDevice } = await supabase
      .from('device_telemetry')
      .select('force_action')
      .eq('machine_id', deviceId)
      .single();

    if (remoteDevice && remoteDevice.force_action) {
      if (remoteDevice.force_action === 'disable') {
        console.error("🚨 REMOTE KILL SWITCH ACTIVATED 🚨");
        app.exit(0); // Instantly kill the POS
        return;
      }
      if (remoteDevice.force_action === 'update') {
         console.log("Force update requested remotely.");
         // Future: trigger electron-updater
      }
    }

    const deviceInfo = {
      machine_id: deviceId,
      app_version: app.getVersion(),
      hostname: os.hostname(),
      os: os.platform(),
      last_seen: new Date().toISOString()
    };

    // Upsert the device row
    const { error } = await supabase
      .from('device_telemetry')
      .upsert(deviceInfo, { onConflict: 'machine_id' });

    if (error) {
      console.error("Failed to sync device telemetry to Supabase:", error);
    } else {
      console.log("Telemetry synced successfully.");
    }
  } catch (err) {
    if (err.message && !err.message.includes('Row not found')) {
       console.error("Error during telemetry sync:", err);
    }
  }
};

export const startTelemetryLoop = () => {
  // Sync immediately on startup
  syncDeviceTelemetry();

  // And sync every 15 minutes
  setInterval(syncDeviceTelemetry, 15 * 60 * 1000);
};

export const logDeveloperError = async (errorMessage) => {
  try {
    const logData = {
      device_id: deviceId,
      app_version: app.getVersion(),
      error_message: errorMessage ? errorMessage.toString() : 'Unknown Error'
    };

    await supabase.from('developer_logs').insert([logData]);
  } catch (err) {
    console.error("Failed to write to developer logs:", err);
  }
};

import pkg from 'electron-updater';
const { autoUpdater } = pkg;
import { app } from 'electron';
import { logInfo, logError } from './logger.js';

/**
 * Compare two semver strings. Returns:
 *  1  if a > b
 *  0  if a == b
 * -1  if a < b
 */
function compareSemver(a, b) {
  const pa = a.split('.').map(Number);
  const pb = b.split('.').map(Number);
  for (let i = 0; i < 3; i++) {
    if ((pa[i] || 0) > (pb[i] || 0)) return 1;
    if ((pa[i] || 0) < (pb[i] || 0)) return -1;
  }
  return 0;
}

export function initAutoUpdater(mainWindow) {
  autoUpdater.autoDownload = false;
  autoUpdater.autoInstallOnAppQuit = false; // Don't auto-install — prevent downgrades

  autoUpdater.on('checking-for-update', () => {
    logInfo('Updater', 'Checking for updates...');
  });

  autoUpdater.on('update-available', (info) => {
    const currentVersion = app.getVersion();
    const remoteVersion = info.version;

    // Guard: NEVER downgrade
    if (compareSemver(remoteVersion, currentVersion) <= 0) {
      logInfo('Updater', `Ignoring update v${remoteVersion} — current v${currentVersion} is same or newer`);
      return;
    }

    logInfo('Updater', `Genuine update available: v${remoteVersion} (current: v${currentVersion})`);
    mainWindow?.webContents.send('update-available', {
      version: info.version,
      releaseDate: info.releaseDate,
    });
  });

  autoUpdater.on('update-not-available', () => {
    logInfo('Updater', 'App is up to date');
  });

  autoUpdater.on('download-progress', (progress) => {
    mainWindow?.webContents.send('update-progress', {
      percent: Math.round(progress.percent),
      transferred: progress.transferred,
      total: progress.total,
    });
  });

  autoUpdater.on('update-downloaded', (info) => {
    logInfo('Updater', `Update downloaded: v${info.version}`);
    mainWindow?.webContents.send('update-downloaded', {
      version: info.version,
    });
  });

  autoUpdater.on('error', (err) => {
    logError('Updater', err);
  });

  // Check for updates 15 seconds after launch
  setTimeout(() => {
    autoUpdater.checkForUpdates().catch(err => {
      logError('Updater', err);
    });
  }, 15000);
}

export function downloadUpdate() {
  autoUpdater.downloadUpdate().catch(err => logError('Updater', err));
}

export function installUpdate() {
  autoUpdater.quitAndInstall(false, true);
}

export async function manualCheckForUpdates(mainWindow) {
  try {
    const result = await autoUpdater.checkForUpdates();
    // result.updateInfo exists if update found, but our guard handles downgrades internally.
    return { success: true, info: result?.updateInfo };
  } catch (err) {
    logError('Updater', err);
    return { success: false, error: err.message };
  }
}

