import { useState, useEffect } from 'react';
import { Clock, CheckCircle, Trash2, AlertCircle, X } from 'lucide-react';
import { useApp } from '../context/AppContext';

export default function Credits() {
  const { darkMode, addToast, isOwner } = useApp();
  const dm = darkMode;

  const [credits, setCredits] = useState([]);
  const [settleModal, setSettleModal] = useState(null); // { credit, amount }
  const [settleAmount, setSettleAmount] = useState('');

  useEffect(() => {
    try {
      const stored = JSON.parse(localStorage.getItem('sz_credits') || '[]');
      setCredits(stored);
    } catch { setCredits([]); }
  }, []);

  const save = (updated) => {
    setCredits(updated);
    localStorage.setItem('sz_credits', JSON.stringify(updated));
  };

  const handleSettle = () => {
    const amount = parseFloat(settleAmount) || 0;
    if (!amount || amount <= 0) return addToast('Enter a valid amount', 'error');

    const updated = credits.map(c => {
      if (c.id !== settleModal.id) return c;
      const newPaid = (c.paid || 0) + amount;
      const newPending = Math.max(0, c.total - newPaid);
      return { ...c, paid: newPaid, pending: newPending };
    }).filter(c => c.pending > 0); // Remove fully settled

    save(updated);
    addToast(`₹${amount} settled for ${settleModal.customer}`, 'success');
    setSettleModal(null);
    setSettleAmount('');
  };

  const handleDelete = (id) => {
    if (!window.confirm('Remove this credit entry?')) return;
    save(credits.filter(c => c.id !== id));
    addToast('Credit entry removed', 'info');
  };

  const totalPending = credits.reduce((s, c) => s + (c.pending || 0), 0);

  const card = `rounded-2xl border shadow-sm ${dm ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`;

  return (
    <div className="p-6 space-y-5">
      <div className="flex justify-between items-end flex-wrap gap-3">
        <div>
          <h2 className={`text-xl font-bold ${dm ? 'text-white' : 'text-slate-800'}`}>Credit / Pay Later</h2>
          <p className={`text-sm mt-0.5 ${dm ? 'text-slate-400' : 'text-slate-500'}`}>Customers with pending balances</p>
        </div>
        {totalPending > 0 && (
          <div className={`flex items-center gap-2 px-4 py-2 rounded-xl ${dm ? 'bg-red-900/30 border border-red-700' : 'bg-red-50 border border-red-200'}`}>
            <AlertCircle className="w-4 h-4 text-red-500" />
            <span className={`text-sm font-bold ${dm ? 'text-red-300' : 'text-red-600'}`}>Total Pending: ₹{totalPending.toLocaleString()}</span>
          </div>
        )}
      </div>

      {credits.length === 0 ? (
        <div className={`${card} p-12 text-center`}>
          <CheckCircle className="w-12 h-12 mx-auto mb-3 text-emerald-400 opacity-50" />
          <p className={`font-semibold ${dm ? 'text-slate-300' : 'text-slate-600'}`}>No pending credits!</p>
          <p className={`text-sm mt-1 ${dm ? 'text-slate-500' : 'text-slate-400'}`}>All customers are settled up.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {credits.map(c => (
            <div key={c.id} className={`${card} p-5 space-y-3`}>
              <div className="flex justify-between items-start">
                <div>
                  <p className={`font-bold text-base ${dm ? 'text-white' : 'text-slate-800'}`}>{c.customer}</p>
                  <p className={`text-xs mt-0.5 ${dm ? 'text-slate-500' : 'text-slate-400'}`}>{c.date}</p>
                </div>
                {!isOwner && (
                  <button onClick={() => handleDelete(c.id)} className="p-1.5 text-red-400 hover:bg-red-50 rounded-lg transition-colors">
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                )}
              </div>

              <p className={`text-xs truncate ${dm ? 'text-slate-500' : 'text-slate-400'}`}>{c.items}</p>

              <div className={`space-y-1.5 text-sm rounded-xl p-3 ${dm ? 'bg-slate-800' : 'bg-slate-50'}`}>
                <div className="flex justify-between">
                  <span className={dm ? 'text-slate-400' : 'text-slate-500'}>Bill Total</span>
                  <span className={`font-semibold ${dm ? 'text-white' : 'text-slate-800'}`}>₹{c.total?.toLocaleString()}</span>
                </div>
                <div className="flex justify-between">
                  <span className={dm ? 'text-slate-400' : 'text-slate-500'}>Paid</span>
                  <span className="font-semibold text-emerald-600">₹{(c.paid || 0).toLocaleString()}</span>
                </div>
                <div className={`flex justify-between border-t pt-1.5 ${dm ? 'border-slate-700' : 'border-slate-200'}`}>
                  <span className="font-bold text-red-500">Pending</span>
                  <span className="font-bold text-red-500">₹{(c.pending || 0).toLocaleString()}</span>
                </div>
              </div>

              {!isOwner && (
                <button
                  onClick={() => { setSettleModal(c); setSettleAmount(String(c.pending)); }}
                  className="w-full py-2.5 bg-emerald-600 text-white rounded-xl font-semibold text-sm hover:bg-emerald-700 transition-all flex items-center justify-center gap-2"
                >
                  <Clock className="w-4 h-4" />
                  Record Payment
                </button>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Settle Modal */}
      {settleModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
          <div className={`w-full max-w-sm mx-4 rounded-2xl shadow-2xl overflow-hidden ${dm ? 'bg-slate-900' : 'bg-white'}`}>
            <div className={`flex items-center justify-between px-5 py-4 border-b ${dm ? 'border-slate-700' : 'border-slate-100'}`}>
              <h3 className={`font-bold ${dm ? 'text-white' : 'text-slate-800'}`}>Record Payment — {settleModal.customer}</h3>
              <button onClick={() => setSettleModal(null)} className="text-slate-400 hover:text-slate-600"><X className="w-5 h-5" /></button>
            </div>
            <div className="p-5 space-y-4">
              {settleModal.items && (
                <div className={`p-3 rounded-xl text-xs font-medium space-y-1 ${dm ? 'bg-slate-800 text-slate-300' : 'bg-slate-50 text-slate-600'}`}>
                   <p className="opacity-70 uppercase tracking-widest text-[10px] mb-1.5 font-bold">Items Purchased</p>
                   <p className="leading-relaxed">{settleModal.items}</p>
                </div>
              )}
              <div className={`flex justify-between text-sm font-semibold p-3 rounded-xl ${dm ? 'bg-red-900/30 text-red-300' : 'bg-red-50 text-red-600'}`}>
                <span>Outstanding</span>
                <span>₹{settleModal.pending?.toLocaleString()}</span>
              </div>
              <div>
                <label className={`text-xs font-semibold uppercase tracking-wide mb-1 block ${dm ? 'text-slate-400' : 'text-slate-500'}`}>Amount Received (₹)</label>
                <input
                  autoFocus
                  type="number"
                  value={settleAmount}
                  onChange={e => setSettleAmount(e.target.value)}
                  className={`w-full px-4 py-3 border-2 rounded-xl text-2xl font-bold text-center outline-none transition-all
                    ${dm ? 'bg-slate-800 border-slate-600 text-white focus:border-emerald-500' : 'bg-slate-50 border-slate-200 text-slate-800 focus:border-emerald-500'}`}
                />
              </div>
              <div className="flex gap-3">
                <button onClick={() => setSettleModal(null)} className={`flex-1 py-2.5 rounded-xl text-sm font-semibold border ${dm ? 'border-slate-600 text-slate-300' : 'border-slate-200 text-slate-600'}`}>Cancel</button>
                <button onClick={handleSettle} className="flex-1 py-2.5 rounded-xl text-sm font-semibold bg-emerald-600 text-white hover:bg-emerald-700">Confirm</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Plus, Search, Phone, Mail, Edit, Trash2, X } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { playSound } from '../utils/sounds';

export default function Customers() {
  const { customers, setCustomers, darkMode, addToast, isOwner } = useApp();
  const dm = darkMode;
  const [search, setSearch] = useState('');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState(null);
  const [formData, setFormData] = useState({ name: '', phone: '', email: '' });

  const card = `rounded-2xl border shadow-sm ${dm ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`;
  const th = `px-5 py-3 text-left text-xs font-semibold uppercase tracking-wide ${dm ? 'text-slate-400 bg-slate-800' : 'text-slate-500 bg-slate-50'}`;
  const inputCls = `w-full px-4 py-3 rounded-xl text-sm border outline-none transition-all ${dm ? 'bg-slate-800 border-slate-700 text-white focus:border-blue-500' : 'bg-slate-50 border-slate-200 focus:border-blue-500'}`;

  // Safe checks since context could be empty
  const safeCustomers = customers || [];
  const filtered = safeCustomers.filter(c => c.name.toLowerCase().includes(search.toLowerCase()) || c.phone.includes(search));

  const openModal = (customer = null) => {
    playSound('tap');
    if (customer) {
      setEditingCustomer(customer);
      setFormData({ name: customer.name, phone: customer.phone, email: customer.email });
    } else {
      setEditingCustomer(null);
      setFormData({ name: '', phone: '', email: '' });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    playSound('tap');
    setIsModalOpen(false);
    setEditingCustomer(null);
    setFormData({ name: '', phone: '', email: '' });
  };

  const handleSave = (e) => {
    e.preventDefault();
    if (!formData.name.trim() || !formData.phone.trim()) {
      addToast('Name and phone are required', 'warning');
      return;
    }

    if (editingCustomer) {
      setCustomers(safeCustomers.map(c => c.id === editingCustomer.id ? { ...c, ...formData } : c));
      addToast('Customer updated successfully!', 'success');
    } else {
      const newCustomer = {
        id: Date.now(),
        ...formData,
        orders: 0,
        total: 0,
        lastOrder: '-'
      };
      setCustomers([...safeCustomers, newCustomer]);
      addToast('Customer added successfully!', 'success');
    }
    closeModal();
  };

  const handleDelete = (id) => {
    if (window.confirm('Are you sure you want to delete this customer?')) {
      playSound('error');
      setCustomers(safeCustomers.filter(c => c.id !== id));
      addToast('Customer deleted', 'info');
    }
  };

  return (
    <div className="p-6 space-y-5">
      <div className="flex justify-between items-end">
        <div>
          <h2 className={`text-xl font-bold ${dm ? 'text-white' : 'text-slate-800'}`}>Customers</h2>
          <p className={`text-sm mt-0.5 ${dm ? 'text-slate-400' : 'text-slate-500'}`}>Customer database and purchase history</p>
        </div>
        {!isOwner && (
          <button onClick={() => openModal()} className="flex items-center gap-2 px-4 py-2.5 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 transition-colors shadow-lg shadow-blue-500/30">
            <Plus className="w-4 h-4" /> Add Customer
          </button>
        )}
      </div>

      {/* Summary */}
      <div className="grid grid-cols-3 gap-4">
        {[
          { label: 'Total Customers', value: safeCustomers.length, fmt: 'num' },
          { label: 'Total Revenue', value: safeCustomers.reduce((s,c)=>s+(c.total||0),0), fmt: 'curr' },
          { label: 'Avg. Order Value', value: safeCustomers.length ? Math.round(safeCustomers.reduce((s,c)=>s+(c.total||0),0) / Math.max(1, safeCustomers.reduce((s,c)=>s+(c.orders||0),0))) : 0, fmt: 'curr' },
        ].map(s => (
          <div key={s.label} className={`${card} p-4`}>
            <p className={`text-xs font-medium ${dm ? 'text-slate-400' : 'text-slate-500'}`}>{s.label}</p>
            <p className={`text-2xl font-bold mt-1 ${dm ? 'text-white' : 'text-slate-800'}`}>{s.fmt === 'curr' ? `₹${s.value.toLocaleString()}` : s.value}</p>
          </div>
        ))}
      </div>

      <div className={`${card} overflow-hidden`}>
        <div className={`px-5 py-3.5 border-b flex items-center gap-3 ${dm ? 'border-slate-700' : 'border-slate-100'}`}>
          <Search className="w-4 h-4 text-slate-400" />
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search by name or phone..."
            className={`flex-1 text-sm outline-none bg-transparent ${dm ? 'text-white placeholder-slate-500' : 'text-slate-800'}`} />
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm whitespace-nowrap">
            <thead><tr className={`border-b ${dm ? 'border-slate-700' : 'border-slate-100'}`}>
              <th className={th}>Name</th>
              <th className={th}>Contact</th>
              <th className={th + ' text-right'}>Orders</th>
              <th className={th + ' text-right'}>Total Spent</th>
              <th className={th}>Last Order</th>
              {!isOwner && <th className={th + ' text-right'}>Actions</th>}
            </tr></thead>
            <tbody className={`divide-y ${dm ? 'divide-slate-700' : 'divide-slate-100'}`}>
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan={6} className={`px-5 py-8 text-center text-sm ${dm ? 'text-slate-400' : 'text-slate-500'}`}>
                    No customers found matching "{search}"
                  </td>
                </tr>
              ) : filtered.map(c => (
                <tr key={c.id} className={`transition-colors ${dm ? 'hover:bg-slate-800/80' : 'hover:bg-slate-50'}`}>
                  <td className="px-5 py-3.5">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 bg-blue-100 text-blue-700 rounded-full flex items-center justify-center text-sm font-bold shadow-sm">
                        {c.name.charAt(0).toUpperCase()}
                      </div>
                      <span className={`font-semibold ${dm ? 'text-white' : 'text-slate-800'}`}>{c.name}</span>
                    </div>
                  </td>
                  <td className="px-5 py-3.5">
                    <div className={`text-xs space-y-1 ${dm ? 'text-slate-400' : 'text-slate-500'}`}>
                      <div className="flex items-center gap-1.5"><Phone className="w-3 h-3 text-blue-500" />{c.phone}</div>
                      {c.email && <div className="flex items-center gap-1.5"><Mail className="w-3 h-3 text-emerald-500" />{c.email}</div>}
                    </div>
                  </td>
                  <td className={`px-5 py-3.5 text-right font-semibold ${dm ? 'text-slate-300' : 'text-slate-700'}`}>{c.orders || 0}</td>
                  <td className="px-5 py-3.5 text-right font-bold text-green-600">₹{(c.total || 0).toLocaleString()}</td>
                  <td className={`px-5 py-3.5 text-xs ${dm ? 'text-slate-400' : 'text-slate-500'}`}>{c.lastOrder || '-'}</td>
                  {!isOwner && (
                    <td className="px-5 py-3.5 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <button onClick={() => openModal(c)} className="p-1.5 text-slate-400 hover:text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-500/10 rounded-lg transition-colors">
                          <Edit className="w-4 h-4" />
                        </button>
                        <button onClick={() => handleDelete(c.id)} className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-lg transition-colors">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className={`w-full max-w-md rounded-3xl shadow-2xl ${dm ? 'bg-slate-900 border border-slate-700' : 'bg-white'}`}>
            <div className={`flex items-center justify-between p-6 border-b ${dm ? 'border-slate-800' : 'border-slate-100'}`}>
              <h3 className={`text-xl font-bold ${dm ? 'text-white' : 'text-slate-800'}`}>
                {editingCustomer ? 'Edit Customer' : 'Add New Customer'}
              </h3>
              <button onClick={closeModal} className={`p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors ${dm ? 'text-slate-400' : 'text-slate-500'}`}>
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleSave} className="p-6 space-y-4">
              <div>
                <label className={`block text-xs font-bold uppercase tracking-wider mb-2 ${dm ? 'text-slate-400' : 'text-slate-500'}`}>Full Name *</label>
                <input 
                  required
                  autoFocus
                  placeholder="e.g. John Doe"
                  className={inputCls} 
                  value={formData.name} 
                  onChange={e => setFormData({...formData, name: e.target.value})} 
                />
              </div>
              <div>
                <label className={`block text-xs font-bold uppercase tracking-wider mb-2 ${dm ? 'text-slate-400' : 'text-slate-500'}`}>Phone Number *</label>
                <input 
                  required
                  placeholder="e.g. +91 9876543210"
                  className={inputCls} 
                  value={formData.phone} 
                  onChange={e => setFormData({...formData, phone: e.target.value})} 
                />
              </div>
              <div>
                <label className={`block text-xs font-bold uppercase tracking-wider mb-2 ${dm ? 'text-slate-400' : 'text-slate-500'}`}>Email Address (Optional)</label>
                <input 
                  type="email"
                  placeholder="e.g. john@email.com"
                  className={inputCls} 
                  value={formData.email} 
                  onChange={e => setFormData({...formData, email: e.target.value})} 
                />
              </div>

              <div className="pt-4 flex gap-3">
                <button type="button" onClick={closeModal} className={`flex-1 py-3 rounded-xl font-bold transition-colors ${dm ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                  Cancel
                </button>
                <button type="submit" className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 hover:bg-blue-700 transition-colors">
                  Save Customer
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import {
  ResponsiveContainer, AreaChart, Area, BarChart, Bar,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, PieChart, Pie, Cell, Sector
} from 'recharts';
import { IndianRupee, TrendingUp, TrendingDown, AlertCircle, Receipt, ArrowUpRight, ArrowDownRight, PackageX, Users } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { useNavigate } from 'react-router-dom';

// --- Static dummy data removed for live database integration ---


export default function Dashboard() {
  const { darkMode, products, sales, expenses, purchases, currentUser } = useApp();
  const dm = darkMode;
  const navigate = useNavigate();

  // Time-aware greeting
  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';
  const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

  const todayStr = new Date().toISOString().split('T')[0];
  const todaySales = useMemo(() => 
    (sales || []).filter(s => (s.date || s.created_at || '').startsWith(todayStr)).reduce((sum, s) => sum + (s.total || 0), 0),
  [sales, todayStr]);

  const monthlyRev = useMemo(() => 
    (sales || []).reduce((sum, s) => sum + (s.total || 0), 0),
  [sales]);

  const totalExpense = useMemo(() => 
    (expenses || []).reduce((sum, e) => sum + (e.amount || 0), 0),
  [expenses]);

  const pendingPayments = useMemo(() => 
    (purchases || []).reduce((sum, p) => sum + ((p.total || 0) - (p.paid || 0)), 0),
  [purchases]);

  const chartData = useMemo(() => {
    // Generate last 7 days for chart
    const days = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    return [0,1,2,3,4,5,6].map(offset => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - offset));
      const dayStr = d.toISOString().split('T')[0];
      const daySalesArr = sales.filter(s => (s.date || s.created_at || '').startsWith(dayStr));
      const daySales = daySalesArr.reduce((sum, s) => sum + (s.total || 0), 0);
      const dayCost = daySalesArr.reduce((sum, s) => {
        return sum + (s.items || []).reduce((itemSum, item) => itemSum + ((item.cost || 0) * item.qty), 0);
      }, 0);
      return { day: days[d.getDay()], sales: daySales, profit: daySales - dayCost }; 
    });
  }, [sales]);

  // Inventory Health
  const { lowStock, outOfStock } = useMemo(() => {
    let low = 0, out = 0;
    (products || []).forEach(p => {
      if (p.stock <= 0) out++;
      else if (p.stock <= 10) low++;
    });
    return { lowStock: low, outOfStock: out };
  }, [products]);

  // Payment Liquidity (Cash vs UPI)
  const paymentSplit = useMemo(() => {
    let cash = 0, online = 0;
    (sales || []).forEach(s => {
      if (s.paymentMethod === 'Cash') cash += s.total || 0;
      else online += s.total || 0;
    });
    return [
      { name: 'Cash', value: cash, color: '#3b82f6' },
      { name: 'Online / UPI', value: online, color: '#8b5cf6' }
    ].filter(d => d.value > 0);
  }, [sales]);

  // Top VIP Customers
  const topCustomers = useMemo(() => {
    // Assuming walk-in for now, but grouping by a hypothetical customer ID if available
    // For now we map true recent high-value sales as "VIP Transactions" or basic grouping
    // Since we don't have a separate 'customers' array deep linked yet, we'll aggregate by payment source or just show top invoices.
    return sales.slice().sort((a,b) => b.total - a.total).slice(0, 5);
  }, [sales]);

  const topProducts = useMemo(() => {
    const itemCounts = {};
    sales.forEach(s => {
      s.items?.forEach(item => {
        itemCounts[item.name] = (itemCounts[item.name] || 0) + item.qty;
      });
    });
    return Object.entries(itemCounts)
      .map(([name, qty]) => ({ name, sales: qty }))
      .sort((a,b) => b.sales - a.sales)
      .slice(0, 5);
  }, [sales]);

  const maxTopProducts = useMemo(() => {
    let m = 0;
    topProducts.forEach(d => {
      if (d.sales > m) m = d.sales;
    });
    return Math.max(m, 10);
  }, [topProducts]);

  const maxSalesLine = useMemo(() => {
    let m = 0;
    chartData.forEach(d => {
      if (d.sales > m) m = d.sales;
      if (d.profit > m) m = d.profit;
    });
    return Math.max(m, 100);
  }, [chartData]);

  const card = `rounded-2xl border shadow-sm transition-all hover:shadow-md ${dm ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`;

  return (
    <div className="p-6 space-y-6">
