               <RefreshCw className="w-4 h-4 text-sky-500" /> Cloud Sync
            </h3>
            <div className="flex items-center justify-between">
              <div>
                <p className={`font-medium text-sm ${dm ? 'text-white' : 'text-slate-800'}`}>Auto Cloud Sync</p>
